#include <stdio.h>
#include <stdlib.h>

// Define the structure for a linked list node
typedef struct ListNode {
    int val;
    struct ListNode* next;
} ListNode;

// Function to detect the start of a cycle in a linked list
ListNode* detectCycle(ListNode* head) {
    // Create a set to store visited nodes
    ListNode** visited = (ListNode**)malloc(10000 * sizeof(ListNode*));
    int size = 0;

    // Traverse the linked list
    while (head != NULL) {
        // Check if the current node is already in the set
        for (int i = 0; i < size; i++) {
            if (visited[i] == head) {
                free(visited);
                return head;
            }
        }

        // Add the current node to the set
        visited[size++] = head;

        // Move to the next node
        head = head->next;
    }

    // If no cycle is found, free the set and return NULL
    free(visited);
    return NULL;
}

